import{_ as a,o as t,c as n,an as s}from"./chunks/framework.D5fFzH9V.js";const g=JSON.parse('{"title":"Making changes","description":"Guidelines for contributing changes to the handbook, including sensitivity and review expectations.","frontmatter":{"title":"Making changes","description":"Guidelines for contributing changes to the handbook, including sensitivity and review expectations."},"headers":[],"relativePath":"making-changes.md","filePath":"making-changes.md"}'),i={name:"making-changes.md"};function o(r,e,l,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /making-changes.md for this page in Markdown format</div><h1 id="making-changes" tabindex="-1">Making changes <a class="header-anchor" href="#making-changes" aria-label="Permalink to &quot;Making changes&quot;">​</a></h1><h2 id="implement-small-changes-immediately" tabindex="-1">Implement small changes immediately <a class="header-anchor" href="#implement-small-changes-immediately" aria-label="Permalink to &quot;Implement small changes immediately&quot;">​</a></h2><p>Don&#39;t keep them for later (it won&#39;t happen). If you don&#39;t have the time to document a larger topic, consider <a href="https://gitlab.internal.syslifters.com/docs/public/-/issues" target="_blank" rel="noreferrer">creating an issue</a> to not forget about it.</p><p>The handbook doesn&#39;t have to include everything at once. Make small changes iteratively.</p><h2 id="present-large-changes-in-the-daily-standup" tabindex="-1">Present large changes in the daily standup <a class="header-anchor" href="#present-large-changes-in-the-daily-standup" aria-label="Permalink to &quot;Present large changes in the daily standup&quot;">​</a></h2><p>If you make significant changes, or add large content pieces, please present them in our daily standup.</p><h2 id="don-t-publish-sensitive-information" tabindex="-1">Don&#39;t publish sensitive information <a class="header-anchor" href="#don-t-publish-sensitive-information" aria-label="Permalink to &quot;Don&#39;t publish sensitive information&quot;">​</a></h2><p>Our documentation should be public by default.<br> However, don&#39;t add contents that:</p><ul><li>are out there on the Internet (rather add links)</li><li>have copyright restrictions</li><li>contain sensitive information, like <ul><li>customer names or data (without agreement)</li><li>URLs or targets or our pentesting projects</li><li>security findings</li><li>personal information (without agreement)</li><li>data that might pose a relevant risk to us or our company.</li></ul></li></ul><p>Link to non-public content (like the <a href="https://syslifters.sysre.pt/projects/5086e509-4fca-4d99-aa2a-404feeda69a7/notes/" target="_blank" rel="noreferrer">Syslifters Knowledge Base</a>), if necessary.<br> If non-public documentation is non-public intentionally, document it there. In markdown files, use the frontmatter syntax, e.g.:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">note</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Non-public due to copyright reasons</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><h2 id="merge-requests-for-change-reviews" tabindex="-1">Merge requests for change reviews <a class="header-anchor" href="#merge-requests-for-change-reviews" aria-label="Permalink to &quot;Merge requests for change reviews&quot;">​</a></h2><p>Create a new branch and ask for a merge request review from colleagues if:</p><ul><li>The contents might contain sensitive information, like <ul><li>redacted screenshots (is there anything unredacted left)</li><li>shell commands (might contain sensitive options)</li></ul></li><li>The change contains significant changes in our working procedures.</li><li>You are unsure, need further inputs, etc.</li><li>Never merge data to the main branch that is not supposed to be public (yet).</li></ul><h2 id="use-content-pieces-for-documentation" tabindex="-1">Use content pieces for documentation <a class="header-anchor" href="#use-content-pieces-for-documentation" aria-label="Permalink to &quot;Use content pieces for documentation&quot;">​</a></h2><p>Add your information to existing or new <code>.md</code> files. Add new markdown files to the correct directory (e.g., <code>/pentesting-manual/</code>, <code>/organization/</code>; otherwise the navigation in the sidebar breaks when opening the page).</p><p>All content files should have a frontmatter block, at least with a <code>title</code> and a <code>description</code> attribute:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>You can use AI to generate a suitable description. The description is used for html <code>meta</code> tags and in <a href="/llms.txt">llms.txt</a>. All titles and menu entries should be in sentence case.</p><p>Add <code>search: false</code> to frontmatter to exlude the page from the handbook search.</p><p>Images and files should have human-readable names. Images live in the /docs/public/images directory, binary files in /docs/public/assets.</p><h2 id="use-blog-posts-for-short-lived-information" tabindex="-1">Use blog posts for short-lived information <a class="header-anchor" href="#use-blog-posts-for-short-lived-information" aria-label="Permalink to &quot;Use blog posts for short-lived information&quot;">​</a></h2><p>The contents of handbook articles should kept up to date as long as it is feasible for us. If we want to publish contents that might change in the future, are one-shot initiatives, or it is foreseeable that we have no interest in keeping it up to date, we can publish the information as a <a href="/blog/">blog post</a>.</p><p>Blog posts have a timestamp and readers can judge for themselves if the content is up-to-date.<br> We don&#39;t have a target of writing X blog posts per month.</p><p>Use or adapt the following prompt to generate a cover image (e.g., using Gemini 3.1 Pro):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create a cover image in format 1920 x 1080px for this blog post.</span></span>
<span class="line"><span>* Monochrome minimalist vector illustration: black shapes on a light gray background with no color accents.</span></span>
<span class="line"><span>* Flat, high-contrast silhouettes: icons and symbols rendered as solid geometric forms.</span></span>
<span class="line"><span>* Modernist / Bauhaus-inspired: simple geometry, strong negative space, balanced composition.</span></span>
<span class="line"><span>* Poster/icon aesthetic: clean edges, minimal detail, a few abstract line/dot elements for texture and motion. </span></span>
<span class="line"><span>* No text</span></span></code></pre></div><p>Blog posts have the following frontmatter/metadata fields:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>pageClass: blog-page</span></span>
<span class="line"><span>title: </span></span>
<span class="line"><span>author: </span></span>
<span class="line"><span>tags: </span></span>
<span class="line"><span>date: YYYY-MM-DD</span></span>
<span class="line"><span>cover: /images/xyz.png</span></span>
<span class="line"><span>---</span></span></code></pre></div><h2 id="how-to-implement-a-change" tabindex="-1">How to implement a change <a class="header-anchor" href="#how-to-implement-a-change" aria-label="Permalink to &quot;How to implement a change&quot;">​</a></h2><p>The easiest way to implement a change is to use the <a href="https://gitlab.internal.syslifters.com/-/ide/project/docs/public/edit/main/-/" target="_blank" rel="noreferrer">GitLab web IDE</a> (the link if for the main branch).</p><p>The contents are in <code>.md</code> files in the <code>/docs/</code> directory. Put images to <code>/docs/public/images/</code> and other files to <code>/docs/public/assets/</code>.<br> Navigation and other site settings are in <code>/docs/.vitepress/config.ts</code>.</p><p>Fix typos and make small changes that don&#39;t need approval directly in the main branch. Create a new branch and a merge request for other changes.</p><p>You can also check out the project to your developer machine and run the dev server using <code>npm run de</code> (<code>npm run dev -- --host 0.0.0.0</code> to bind the port to all interfaces).</p><h3 id="redirect-after-renaming-files-and-directories" tabindex="-1">Redirect after renaming files and directories <a class="header-anchor" href="#redirect-after-renaming-files-and-directories" aria-label="Permalink to &quot;Redirect after renaming files and directories&quot;">​</a></h3><p>If you rename a files or a directory, make sure that the old path redirects to the new destination. Add the old and the new path to <code>/docs/redirects.txt</code> and VitePress will handle the redirect for you.</p>`,36)])])}const m=a(i,[["render",o]]);export{g as __pageData,m as default};
